$(document).ready(function(){$(window).scroll(function(){$(window).scrollTop()>=5?$(".header").addClass("header--animation"):$(".header").removeClass("header--animation")}),$(".logos-holder").slick({arrows:!1,draggable:!1,autoplay:!1,speed:500,slidesToShow:5,slidesToScroll:5,swipe:!1,touchMove:!1}),$(".btn-load-more").click(function(){$(this).closest("body").find(".logos-holder").slick("slickNext")}),document.querySelectorAll(".form-control").forEach(function(o){o.addEventListener("keyup",function(){console.log(this.value),this.setAttribute("value",this.value)})})});